function user_profile_uploader_enqueue_scripts() {
    wp_enqueue_script( 'user-profile-uploader', plugins_url( 'user-profile-uploader.js', __FILE__ ), array( 'jquery' ), '1.0', true );
}
add_action( 'admin_enqueue_scripts', 'user_profile_uploader_enqueue_scripts' );

function user_profile_uploader_form() {
    ?>
    <form action="<?php echo admin_url( 'admin-post.php' ); ?>" method="post" enctype="multipart/form-data">
        <label for="profile_picture">Profile Picture:</label>
        <input type="file" name="profile_picture" id="profile_picture">

        <label for="documents">Documents:</label>
        <input type="file" name="documents[]" id="documents" multiple>

        <input type="submit" name="submit" value="Upload">
    </form>
    <?php
}
add_action( 'show_user_profile', 'user_profile_uploader_form' );

function user_profile_uploader_process_upload() {
    if ( isset( $_POST['submit'] ) ) {
        $profile_picture = $_FILES['profile_picture'];
        $documents = $_FILES['documents'];

        // Upload profile picture
        $profile_picture_upload = wp_upload_bits( $profile_picture['name'], null, file_get_contents( $profile_picture['tmp_name'] ) );
        update_user_meta( get_current_user_id(), 'profile_picture', $profile_picture_upload['url'] );

        // Upload documents
        foreach ( $documents as $document ) {
            $document_upload = wp_upload_bits( $document['name'], null, file_get_contents( $document['tmp_name'] ) );
            update_user_meta( get_current_user_id(), 'documents', $document_upload['url'] );
        }
    }
}
add_action( 'admin_post_nopriv', 'user_profile_uploader_process_upload' );